// Combine original data with request_id and add poll counter
const originals = $('Store Original Columns').all();
const researchResults = $input.all();

return originals.map((orig, i) => ({
  json: {
    ...orig.json,
    request_id: researchResults[i]?.json?.request_id || null,
    poll_count: 0
  }
}));

// Combine original data with research status
const waitData = $('Wait 30s').all();
const statusResults = $input.all();

return waitData.map((orig, i) => {
  const status = statusResults[i]?.json || {};
  return {
    json: {
      ...orig.json,
      poll_count: (orig.json.poll_count || 0) + 1,
      research_status: status.status || 'unknown',
      research_result: status
    }
  };
});

// Merge original data with research results - ONLY for existing columns
const items = $input.all();

const isEmpty = (val) => val === undefined || val === null || val === '';

// Helper function to normalize strings for matching
const normalize = (str) => {
  if (!str) return '';
  return str.toLowerCase().replace(/[^a-z0-9]/g, '');
};

// Helper function to find matching field in extracted data
const findMatchingField = (colName, extracted) => {
  const normalizedCol = normalize(colName);

  // 1. Exact match (case-insensitive)
  for (const key in extracted) {
    if (normalize(key) === normalizedCol) {
      return extracted[key];
    }
  }

  // 2. Partial match (column name contains research field or vice versa)
  for (const key in extracted) {
    const normalizedKey = normalize(key);
    if (normalizedCol.includes(normalizedKey) || normalizedKey.includes(normalizedCol)) {
      return extracted[key];
    }
  }

  // 3. Common field name variations
  const variations = {
    'cto': ['cto', 'chieftechnologyofficer', 'chieftech', 'technologyofficer'],
    'ceo': ['ceo', 'chiefexecutiveofficer', 'chiefexec', 'executiveofficer'],
    'cfo': ['cfo', 'chieffinancialofficer', 'financialofficer'],
    'revenue': ['revenue', 'annualrevenue', 'revenues', 'totalrevenue'],
    'headquarters': ['headquarters', 'hq', 'hqbased', 'location', 'headquarter'],
    'employees': ['employees', 'noofemployees', 'employeecount', 'staff', 'workforce'],
    'founded': ['founded', 'foundedyear', 'yearfounded', 'established', 'foundingyear'],
    'funding': ['funding', 'latestfunding', 'recentfunding', 'investment', 'capital'],
    'industry': ['industry', 'sector', 'businesssector'],
    'website': ['website', 'url', 'web', 'site'],
    'domain': ['domain', 'domainname', 'webdomain']
  };

  for (const [variationKey, variationList] of Object.entries(variations)) {
    if (variationList.some(v => normalize(v) === normalizedCol)) {
      // Try to find matching research field
      for (const key in extracted) {
        const normalizedKey = normalize(key);
        if (variationList.some(v => normalize(v) === normalizedKey)) {
          return extracted[key];
        }
      }
    }
  }

  return null;
};

return items.map((item) => {
  const original = item.json;
  const research = original.research_result || {};
  const originalColumns = original._original_columns || [];

  // Try multiple possible locations for structured output
  let extracted = {};

  // 1. Check structured_output (primary expected location)
  if (research.structured_output && typeof research.structured_output === 'object') {
    extracted = research.structured_output;
  }
  // 2. Check if content is a JSON object (structured output)
  else if (research.content && typeof research.content === 'object') {
    extracted = research.content;
  }
  // 3. Try parsing content if it's a JSON string
  else if (research.content && typeof research.content === 'string') {
    try {
      const parsed = JSON.parse(research.content);
      if (typeof parsed === 'object') extracted = parsed;
    } catch (e) { /* Not JSON, skip */ }
  }
  // 4. Check output field
  else if (research.output && typeof research.output === 'object') {
    extracted = research.output;
  }
  // 5. Check data field
  else if (research.data && typeof research.data === 'object') {
    extracted = research.data;
  }
  // 6. Check result field
  else if (research.result && typeof research.result === 'object') {
    extracted = research.result;
  }

  // Build merged object - ONLY include columns that exist in original
  const merged = {};

  // For each original column, try to fill it from research
  originalColumns.forEach((colName) => {
    // Skip internal fields
    if (colName.startsWith('_')) {
      return;
    }

    // If original has a value, keep it
    if (!isEmpty(original[colName])) {
      merged[colName] = original[colName];
      return;
    }

    // Try to find matching research field using intelligent matching
    const foundValue = findMatchingField(colName, extracted);

    // Set value (empty string if not found)
    merged[colName] = foundValue !== null && foundValue !== undefined ? foundValue : '';
  });

  return { json: merged };
});

// Store original column names and build dynamic output schema
const items = $input.all();

// Get column names from first item (all items should have same structure)
const firstItem = items[0]?.json || {};
const originalColumns = Object.keys(firstItem).filter(col => !col.startsWith('_'));

// Build dynamic output schema based on original columns
// Map column names to research-friendly descriptions
const columnDescriptions = {
  'company_name': 'Official company name',
  'website': 'Company website URL',
  'domain': 'Company domain name',
  'hq_based': 'Headquarters location',
  'headquarters': 'Headquarters location',
  'no_of_employees': 'Number of employees',
  'employee_count': 'Number of employees',
  'employees': 'Number of employees',
  'industry': 'Industry sector',
  'founded_year': 'Year company was founded',
  'founded': 'Year company was founded',
  'ceo': 'Current CEO name',
  'cto': 'Current CTO (Chief Technology Officer) name',
  'cfo': 'Current CFO (Chief Financial Officer) name',
  'revenue': 'Annual revenue or latest revenue figure',
  'latest_funding': 'Latest funding round details',
  'funding': 'Latest funding information',
  'description': 'Brief company description',
  'about': 'Company description or about information'
};

const outputSchemaProperties = {};
originalColumns.forEach(col => {
  // Use custom description if available, otherwise generate one
  const description = columnDescriptions[col.toLowerCase()] || 
    `Information about ${col.replace(/_/g, ' ')}`;
  outputSchemaProperties[col] = {
    type: 'string',
    description: description
  };
});

const outputSchema = { properties: outputSchemaProperties };

return items.map((item, index) => {
  const company = item.json.company_name || item.json.domain || item.json.website || 'unknown';
  const researchInput = 'Research company ' + company + '. Find information about: ' + originalColumns.join(', ') + '.';

  return {
    json: {
      ...item.json,
      _row_number: index + 2,
      _original_columns: originalColumns,
      research_body: {
        input: researchInput,
        output_schema: outputSchema
      }
    }
  };
});
